{
 "level": "A1‚ÄìA2",
 "intro": "In this topic you will learn <strong>basic English question forms</strong>: yes/no questions, wh-questions and the word order that makes a sentence a question.",
 "rules": [
 {
 "label": "YES / NO QUESTIONS",
 "color": "emerald",
 "text": "Questions that can be answered with <strong>yes</strong> or <strong>no</strong>:",
 "example": "Do you like tea? / Are you ready? / Can you help?"
 },
 {
 "label": "WH-QUESTIONS",
 "color": "blue",
 "text": "Questions that begin with a question word:",
 "example": "What do you want? / Where are you going? / Why is she here?"
 },
 {
 "label": "WORD ORDER",
 "color": "amber",
 "text": "In many English questions, an auxiliary verb stands before the subject:",
 "example": "Auxiliary + subject + main verb"
 }
 ]
}

{
 "title": "1. What belongs to question forms?",
 "intro": "These are the main question patterns you will meet in this topic:",
 "items": [
 {
 "label": "Yes / No",
 "title": "General questions",
 "subtitle": "A yes or no answer"
 },
 {
 "label": "Wh",
 "title": "Wh-Questions",
 "subtitle": "Questions with who, what, where, when, why, how"
 },
 {
 "label": "Answers",
 "title": "Answers to Questions",
 "subtitle": "Short and full answers"
 },
 {
 "label": "Alternative",
 "title": "Alternative Questions",
 "subtitle": "A choice between options"
 },
 {
 "label": "Tags",
 "title": "Question Tags",
 "subtitle": "Short questions at the end of a sentence"
 },
 {
 "label": "Negative",
 "title": "Negative Questions",
 "subtitle": "Questions with a negative form"
 }
 ]
}

{
 "title": "2. Basic word order in questions",
 "sections": [
 {
 "label": "Subject and verb inversion",
 "color": "emerald",
 "description": "In questions <strong>the auxiliary verb is placed before the subject</strong>. This is called an inversion.",
 "examples": [
 {
 "en": "You are ready. ‚Üí Are you ready?",
 "ua": "You are ready. ‚Üí Are you ready?"
 },
 {
 "en": "She can swim. ‚Üí Can she swim?",
 "ua": "She can swim. ‚Üí Can she swim?"
 },
 {
 "en": "They will come. ‚Üí Will they come?",
 "ua": "They will come. ‚Üí Will they come?"
 }
 ]
 },
 {
 "label": "General question formula",
 "color": "blue",
 "description": "Basic question structure in English:",
 "examples": [
 {
 "en": "Auxiliary + Subject + Main Verb +...?",
 "ua": "Auxiliary + Subject + Main Verb +...?"
 },
 {
 "en": "Do you speak English?",
 "ua": "Do you speak English?"
 },
 {
 "en": "Is he coming tonight?",
 "ua": "Is he coming tonight?"
 }
 ],
 "note": "üìå The auxiliary verb always precedes the subject in questions!"
 }
 ]
}

{
 "title": "3. Yes/No Questions ‚Äî General questions",
 "sections": [
 {
 "label": "With DO/DOES/DID",
 "color": "emerald",
 "description": "In simple tenses (Simple) we use <strong>do/does/did</strong> to form questions.",
 "examples": [
 {
 "en": "Do you like coffee?",
 "ua": "Do you like coffee?"
 },
 {
 "en": "Does she work here?",
 "ua": "Does she work here?"
 },
 {
 "en": "Did they arrive on time?",
 "ua": "Did they arrive on time?"
 }
 ]
 },
 {
 "label": "With TO BE",
 "color": "sky",
 "description": "With the verb <strong>to be</strong> we make an inversion - we put be before the subject.",
 "examples": [
 {
 "en": "Are you Ready? <strong>modal verbs</strong> (can, will, should, must, may) make an inversion.",
 "ua": "Are you Ready? <strong>modal verbs</strong> (can, will, should, must, may) make an inversion."
 },
 {
 "en": "Is she at home?",
 "ua": "Is she at home?"
 },
 {
 "en": "Were they happy?",
 "ua": "Were they happy?"
 }
 ]
 },
 {
 "label": "With modal verbs",
 "color": "purple",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Can you swim?",
 "ua": "Can you swim?"
 },
 {
 "en": "Will she come?",
 "ua": "Will she come?"
 },
 {
 "en": "Should we wait?",
 "ua": "Should we wait?"
 }
 ]
 }
 ]
}

{
 "title": "4. Wh-Questions - Special questions",
 "sections": [
 {
 "label": "Question Words)",
 "color": "emerald",
 "description": "Special questions start with a <strong>question word</strong>:",
 "examples": [
 {
 "en": "What? ",
 "ua": "What? "
 },
 {
 "en": "Where - Where? Kudi?",
 "ua": "Where - Where? Kudi?"
 },
 {
 "en": "When - Koli?",
 "ua": "When - Koli?"
 },
 {
 "en": "Why - Why?",
 "ua": "Why - Why?"
 },
 {
 "en": "Who - Who?",
 "ua": "Who - Who?"
 },
 {
 "en": "How - How?",
 "ua": "How - How?"
 }
 ]
 },
 {
 "label": "Wh-question structure",
 "color": "blue",
 "description": "Special question formula:",
 "examples": [
 {
 "en": "Wh-word + Auxiliary + Subject + Main Verb?",
 "ua": "Wh-word + Auxiliary + Subject + Main Verb?"
 },
 {
 "en": "What do you want?",
 "ua": "What do you want?"
 },
 {
 "en": "Where is she going?",
 "ua": "Where is she going?"
 },
 {
 "en": "Why did they leave?",
 "ua": "Why did they leave?"
 }
 ]
 },
 {
 "label": "Subject Questions",
 "color": "amber",
 "description": "When <strong>Who/What is the subject</strong>, the word order is as in an affirmative sentence (without do/does/did):",
 "examples": [
 {
 "en": "Who called you?",
 "ua": "Who called you?"
 },
 {
 "en": "What happened?",
 "ua": "What happened?"
 },
 {
 "en": "Who knows the answer?",
 "ua": "Who knows the answer?"
 }
 ],
 "note": "üìå If Who/What is the subject, do not add do/does/did!"
 }
 ]
}

{
 "title": "5. Auxiliary verbs in questions",
 "sections": [
 {
 "label": "DO/DOES/DID - for Simple Tenses",
 "color": "emerald",
 "description": "In simple tenses (Present Simple, Past Simple) we use do/does/did as auxiliary:",
 "examples": [
 {
 "en": "Present Simple: Do/Does",
 "ua": "Present Simple: Do/Does"
 },
 {
 "en": "Past Simple: Did",
 "ua": "Past Simple: Did"
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 },
 {
 "label": "TO BE",
 "color": "sky",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Present: am/is/are",
 "ua": "Present: am/is/are"
 },
 {
 "en": "Past: was/were",
 "ua": "Past: was/were"
 }
 ]
 },
 {
 "label": "HAVE/HAS is for Perfect Tenses",
 "color": "purple",
 "description": "In the perfect tenses (Present Perfect, Past Perfect) have/has is an auxiliary verb:",
 "examples": [
 {
 "en": "Present Perfect: have/has",
 "ua": "Present Perfect: have/has"
 },
 {
 "en": "past perfect: had Could",
 "ua": "past perfect: had Could"
 }
 ]
 },
 {
 "label": "Modal verbs - inversion",
 "color": "amber",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Can, Could",
 "ua": "Can, Could"
 },
 {
 "en": "Will, Would",
 "ua": "Will, Would"
 },
 {
 "en": "Should, Must, May",
 "ua": "Should, Must, May"
 }
 ]
 }
 ]
}

{
 "title": "6. Questions in different tenses",
 "sections": [
 {
 "label": "Present Simple",
 "color": "emerald",
 "description": "We use <strong>do/does</strong> (with to be ‚Äî inversion of am/is/are):",
 "examples": [
 {
 "en": "Do you speak English?",
 "ua": "Do you speak English?"
 },
 {
 "en": "Does she live Here? now?\" Simple",
 "ua": "Does she live Here? now?\" Simple"
 },
 {
 "en": "Are you a student?",
 "ua": "Are you a student?"
 }
 ]
 },
 {
 "label": "Present Continuous",
 "color": "sky",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Are you working now?",
 "ua": "Are you working now?"
 },
 {
 "en": "Is she coming?",
 "ua": "Is she coming?"
 },
 {
 "en": "What are they doing?",
 "ua": "What are they doing?"
 }
 ]
 },
 {
 "label": "Past Simple",
 "color": "purple",
 "description": "We use <strong>did</strong> (with to be ‚Äî the inversion of was/were):",
 "examples": [
 {
 "en": "Did you see the movie? left?",
 "ua": "Did you see the movie? left?"
 },
 {
 "en": "Where did she go?",
 "ua": "Where did she go?"
 },
 {
 "en": "Were you at home?",
 "ua": "Were you at home?"
 }
 ]
 },
 {
 "label": "Present Perfect",
 "color": "amber",
 "description": "Inversion <strong>have/has</strong>:",
 "examples": [
 {
 "en": "Have you ever been to Paris?",
 "ua": "Have you ever been to Paris?"
 },
 {
 "en": "Has she finished her work?",
 "ua": "Has she finished her work?"
 },
 {
 "en": "What have they done? Party? Comparison of question types",
 "ua": "What have they done? Party? Comparison of question types"
 }
 ]
 },
 {
 "label": "Future Simple",
 "color": "rose",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Will you come to the party?",
 "ua": "Will you come to the party?"
 },
 {
 "en": "When will she arrive?",
 "ua": "When will she arrive?"
 },
 {
 "en": "What will they do?",
 "ua": "What will they do?"
 }
 ]
 }
 ]
}

{
 "title": "7. Comparing question types",
 "intro": "A quick overview of the main question patterns in English:",
 "rows": [
 {
 "en": "Yes / No Questions",
 "ua": "Yes / No Questions",
 "note": "Do you like tea? ‚Äî yes / no answer"
 },
 {
 "en": "Wh-Questions",
 "ua": "Wh-Questions",
 "note": "What do you want? ‚Äî specific information"
 },
 {
 "en": "Answers to Questions",
 "ua": "Answers to Questions",
 "note": "Yes, I do. / No, she isn‚Äôt."
 },
 {
 "en": "Alternative Questions",
 "ua": "Alternative Questions",
 "note": "Tea or coffee? ‚Äî choice between options"
 },
 {
 "en": "Question Tags",
 "ua": "Question Tags",
 "note": "You like it, don't you? ‚Äî confirmation"
 },
 {
 "en": "Negative Questions",
 "ua": "Negative Questions",
 "note": "Don't you know? ‚Äî surprise or expectation"
 }
 ],
 "warning": "üìå Each question type has its own structure and communicative effect."
}

{
 "title": "8. When to use do/does/did",
 "intro": "Rules for using auxiliary verbs do/does/did:",
 "rows": [
 {
 "en": "Simple Tenses (main verbs)",
 "ua": "Simple Tenses (main verbs)",
 "note": "Do you work? Does she know? Did they go?"
 },
 {
 "en": "NOT with TO BE",
 "ua": "NOT with TO BE",
 "note": "‚ùå Do you are happy? ‚úÖ Are you happy?"
 },
 {
 "en": "NOT with modals",
 "ua": "NOT with modals",
 "note": "‚ùå Do you can swim? ‚úÖ Can you swim?"
 },
 {
 "en": "NOT with have (perfect)",
 "ua": "NOT with have (perfect)",
 "note": "‚ùå Do you have seen? ‚úÖ Have you seen?"
 },
 {
 "en": "NOT in subject questions",
 "ua": "NOT in subject questions",
 "note": "‚ùå Who did call? ‚úÖ Who called?"
 }
 ],
 "warning": "‚öÝÔ∏è Do/Does/Did are ONLY used with main verbs in Simple Tenses!"
}

{
 "title": "9. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Incorrect word order - subject before auxiliary verb.",
 "wrong": "‚ùå You are happy? She can swim?",
 "right": " ‚úÖ <span class=\"font-mono\">Are you happy? Can she swim?</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Using do/does/did with to be.",
 "wrong": "‚ùå Do you are ready? Did you were there?",
 "right": "‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã Were you there?</span>"
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Using do/does/did with modal verbs.",
 "wrong": "‚ùå Do you can help? Did she come? ",
 "right": " ‚úÖ <span class=\"font-mono\">Can you help? Could she come?</span>"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "Incorrect form of the main verb.",
 "wrong": "‚ùå Does she works? Did they go?",
 "right": " ‚úÖ <span class=\"font-mono\">Does she work? Did they go?</span>"
 },
 {
 "label": "Error 5",
 "color": "emerald",
 "title": "Adding do/does/did in questions to the subject.",
 "wrong": "‚ùå Who did call you? What did happen?",
 "right": "‚Äã‚Äã‚Äã‚Äã <span class=\"font-mono\">Who called you? What happened?</span>"
 },
 {
 "label": "Error 6",
 "color": "indigo",
 "title": "Omission of auxiliary verb.",
 "wrong": "‚ùå You like coffee? She speaks English?",
 "right": "‚Äã‚Äã‚Äã‚Äã <span class=\"font-mono\">Do you like coffee? Does she speak English?</span>"
 }
 ]
}

{
